import React, { Component } from 'react';
import './dabutton.css';

export default class Dabutton extends Component {
  render() {
    let isIconLeft = (this.props.iconPos === 'right')? false : true;
    let iconClass = (this.props.iconClass !== undefined)? this.props.iconClass : 'fa fa-circle'; 

    let lefticon = null;
    let righticon = null;
    
    let icon = (
      <i className={iconClass}></i>
    );
    if (isIconLeft) {
      lefticon = icon;
    } else {
      righticon = icon;
    }

    let farOnClick = (this.props.farOnClick !== undefined)? this.props.farOnClick : ()=>{console.log('button clicked')};

    return (
      <div className="Dabutton" onClick={(e)=>{farOnClick()}}>
        {lefticon}&nbsp;
        {this.props.value}&nbsp;
        {righticon}      
      </div>
    );
  }
}
