import React, { Component } from 'react';
import ReactMarkdown from 'react-markdown';
import './blogdetail.css';
import Navbar from '../component/navbar';

export default class BlogDetail extends Component {
  constructor(props) {
    super(props);
    this.state = {
        content : null,
        error : 0
    }

  }

  componentDidMount() {
    let url = new URL(window.location.href);
    let a = url.searchParams.get("a");
    
    if (a === null) {
        this.setState({error: 1});
    }
     
    fetch("/blog/"+a+".md")
       .then((r)=>{return r.text();})
       .then((r)=>{
            if (r.startsWith("<!DOC")) {
                this.setState({error:1});
            } else {
                this.setState({content:r})
            }
        });
  }

  render() { 
    let c = this.state.content;

    if (this.state.error === 1) {
        c = (<h1>BLOG NOT FOUND! GO TO BLOGS PAGE</h1>);
    } else if ( c !== null ) {
        c = (<ReactMarkdown source={c} />);
    }

    return (
      <div className="BlogDetail">
        <Navbar items={navbarItems}/>
        <div className="BlogDetail-Content" style={{height :  (height - 75) + "px"}}>
            {c}
        </div>
      </div>
    );
  }
}

const height = window.innerHeight;

const navbarItems = [
{value: 'Go To Main', iconClass: 'fa fa-home', loc:"/" },
{value: 'Go To Blog', iconClass: 'fa fa-newspaper-o', loc:"/?p=blogs" },
{value: 'Share', iconClass: 'fa fa-share-alt' },
];
