const items_key = "mujdecisy.github.io.dash.items";

const promises = {
    items_get: () => {
        return new Promise(
            (res, rej) => {
                console.log("ITEMS GET PROMISE");
                let items = localStorage.getItem(items_key);
                if (items !== null) res(JSON.parse(items));
                rej();
            }
        );
    },

    items_set: (items) => {
        return new Promise(
            (res, rej) => {
                console.log("ITEMS SET PROMISE");
                localStorage.setItem(items_key, JSON.stringify(items));
                res();
            }
        );
    },

    items_remove: () => {
        return new Promise(
            (res, rej) => {
                console.log("ITEMS REMOVE PROMISE");
                localStorage.removeItem(items_key);
                res();
            }
        );
    }
}

export {
    promises,
    items_key
}