import React, { Component } from 'react';
import './blogs.css';

export default class Blogs extends Component {
  constructor(props) {
    super(props);
    this.state = {
        content : null
    }

    fetch("/blog/metadata.json")
        .then(r=> r.json())
        .then(r=> this.setState({content:r}));
  }


  render() { 
    let c = this.state.content;
    let articles = [];
    if (c !== null) {
        c = c.articles;
        for (let i=0; i<c.length; i++) {
            let a = c[i];
            console.log(a);
            let newdiv = (
                <div key={i}>
                    <div>{a.name}</div>
                    <div>{a.description}</div>
                    <div>{a.date}</div>
                    <a href={a.pagepath}>{a.pagepath}</a>
                </div>
            );
            articles.push(newdiv);
        }
    }  

    return (
        <div>
            {articles}
        </div>
    );
  }
}

const height = window.innerHeight;
